import{_ as a,c as t,o as s,ag as l}from"./chunks/framework.DnwzncJk.js";const h=JSON.parse('{"title":"Rust 中解析 Excel 的库","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"src/rust/知识点-calamine和umya-spreadsheet对比.md","filePath":"src/rust/知识点-calamine和umya-spreadsheet对比.md","lastUpdated":1764326226000}'),n={name:"src/rust/知识点-calamine和umya-spreadsheet对比.md"};function o(r,e,d,i,c,p){return s(),t("div",null,e[0]||(e[0]=[l(`<h1 id="rust-中解析-excel-的库" tabindex="-1">Rust 中解析 Excel 的库 <a class="header-anchor" href="#rust-中解析-excel-的库" aria-label="Permalink to &quot;Rust 中解析 Excel 的库&quot;">​</a></h1><h2 id="👉calamine-和-umya-spreadsheet对比" tabindex="-1">👉<code>calamine</code> 和 <code>umya-spreadsheet</code>对比 <a class="header-anchor" href="#👉calamine-和-umya-spreadsheet对比" aria-label="Permalink to &quot;👉\`calamine\` 和 \`umya-spreadsheet\`对比&quot;">​</a></h2><h3 id="_1️⃣-calamine-放弃" tabindex="-1">1️⃣ calamine（放弃） <a class="header-anchor" href="#_1️⃣-calamine-放弃" aria-label="Permalink to &quot;1️⃣ calamine（放弃）&quot;">​</a></h3><p><code>calamine</code> 是专门用来解析 Excel 的 crate，它支持：</p><ul><li><code>.xls</code>（BIFF 格式）</li><li><code>.xlsx</code>（Office Open XML 格式）</li><li><code>.ods</code>（LibreOffice / OpenOffice 格式）</li></ul><p>但是同时处理这两种格式我们还是使用<code>umya-spreadsheet = &quot;1.1&quot;</code></p><p><strong>定位</strong>：<strong>Rust 中的 Excel 读取库（Read-only）</strong><br><strong>特点</strong>：</p><ul><li>支持 <strong>xlsx</strong>、<strong>xls</strong>、<strong>ods</strong>（OpenDocument Spreadsheet） 等格式。</li><li>专注于<strong>解析和读取</strong> Excel 数据，<strong>不支持写入或修改文件</strong>。</li><li>速度快，内存占用小，适合<strong>数据导入</strong>、<strong>批量读取</strong>。</li><li>API 比较简单，比如：</li></ul><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>use calamine::{open_workbook_auto, Reader};</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let mut workbook = open_workbook_auto(&quot;test.xlsx&quot;)?;</span></span>
<span class="line"><span>if let Some(Ok(range)) = workbook.worksheet_range(&quot;Sheet1&quot;) {</span></span>
<span class="line"><span>    for row in range.rows() {</span></span>
<span class="line"><span>        println!(&quot;{:?}&quot;, row);</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>优点</strong>：</p><ul><li>快速读取大文件。</li><li>格式支持多样（不仅是 Excel，还有 ods）。</li><li>纯读取，避免了误改数据的风险。</li></ul><p><strong>缺点</strong>：</p><ul><li>不能写入或创建新 Excel【calamine 不能用于导出（写入）Excel 文件】</li><li>不支持复杂 Excel 样式（颜色、合并单元格、公式等）。</li></ul><p><strong>适用场景</strong>：</p><ul><li>从 Excel 批量导入数据库（比如你的用户导入接口）。</li><li>报表解析、数据分析前置处理。</li></ul><hr><h3 id="_2️⃣-umya-spreadsheet-使用" tabindex="-1">2️⃣ umya-spreadsheet（使用） <a class="header-anchor" href="#_2️⃣-umya-spreadsheet-使用" aria-label="Permalink to &quot;2️⃣ umya-spreadsheet（使用）&quot;">​</a></h3><p><strong>定位</strong>：<strong>Rust 的 Excel 全功能读写库（Read + Write）</strong><br><strong>特点</strong>：</p><ul><li>完全支持 <code>.xlsx</code> 文件的<strong>创建、读取、修改、保存</strong>。</li><li>支持样式（字体、颜色、背景）、合并单元格、公式、图表等复杂功能。</li><li>API 偏详细，写 Excel 时比 <code>calamine</code> 灵活，但稍复杂。</li><li>不支持 <code>.xls</code>（老 Excel 二进制格式），只支持 <code>.xlsx</code>。</li></ul><p><strong>简单示例</strong>：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>use umya_spreadsheet::*;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let mut book = new_file();</span></span>
<span class="line"><span>let sheet = book.get_sheet_by_name_mut(&quot;Sheet1&quot;).unwrap();</span></span>
<span class="line"><span>sheet.get_cell_mut(&quot;A1&quot;).set_value(&quot;Hello World&quot;);</span></span>
<span class="line"><span>writer::xlsx::write(&amp;book, &quot;output.xlsx&quot;).unwrap();</span></span></code></pre></div><p><strong>优点</strong>：</p><ul><li>能读能写，功能齐全。</li><li>支持 Excel 样式、美化、复杂表格。</li><li>适合生成报表模板。</li></ul><p><strong>缺点</strong>：</p><ul><li>只支持 <code>.xlsx</code>，不支持 <code>.xls</code>。</li><li>相比 <code>calamine</code>，读取速度稍慢，内存占用也更大。</li></ul><p><strong>适用场景</strong>：</p><ul><li>生成带格式的 Excel 报表、导出模板。</li><li>对 Excel 内容做修改再保存。</li><li>需要控制表格样式的导出场景。</li></ul><hr><h3 id="_3️⃣-总结对比表" tabindex="-1">3️⃣ 总结对比表 <a class="header-anchor" href="#_3️⃣-总结对比表" aria-label="Permalink to &quot;3️⃣ 总结对比表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>calamine</th><th>umya-spreadsheet</th></tr></thead><tbody><tr><td>读 <code>.xlsx</code></td><td>✅</td><td>✅</td></tr><tr><td>读 <code>.xls</code></td><td>✅</td><td>❌</td></tr><tr><td>写 <code>.xlsx</code></td><td>❌</td><td>✅</td></tr><tr><td>样式/公式/图表支持</td><td>❌</td><td>✅</td></tr><tr><td>速度（大文件读取）</td><td>🚀 快</td><td>🐢 稍慢</td></tr><tr><td>内存占用</td><td>低</td><td>中等偏高</td></tr><tr><td>适用场景</td><td>数据导入</td><td>报表导出、模板生成</td></tr></tbody></table><p>💡 <strong>结合你的项目</strong>：</p><ul><li><strong>导入用户数据</strong>：用 <code>calamine</code>（支持 <code>.xls</code> 和 <code>.xlsx</code>，读取快）。</li><li><strong>导出 Excel 模板</strong>：用 <code>umya-spreadsheet</code>（能加表头、格式、美化）。</li></ul><hr><p>所以我们<strong>的方案是使用一个混合方案</strong>，导入用 <code>calamine</code>，导出模板用 <code>umya-spreadsheet</code>，这样既兼容老 Excel，又能做漂亮的导出。<br> 导入 <code>.xls</code> 文件时不会报错</p><p>这个我们稍后完善，实现基础功能先实现ok</p><p>更新：考虑到对于依赖的减少，calamine的功能还是不全，所以只能抛弃，转而使用umya-spreadsheet实现我们的导入和导出功能</p>`,36)]))}const g=a(n,[["render",o]]);export{h as __pageData,g as default};
